  sector,
  count(*) as n_trades,
  sum(est_trade_value_usd) / 1000.0 as est_buy_volume_30d_k
from ${trades_30d}
where txn_type = 'buy'
  and sector in ${inputs.trade_sectors.value}
  and coalesce(est_trade_value_usd, 0) >= ${inputs.min_size.value}
group by sector
order by est_buy_volume_30d_k desc

